INSERT INTO meal_plans (id,week_label,generated_by,notes,is_active) VALUES ('06df96a1-3dd1-47d1-8ce9-0cfacbf511d9','Week of May 10-16','claude-opus-4-6','Perishability-first plan. Sun-Mon clear bananas, tomatoes, arugula and the smoked mackerel (208g split across Sun dinner + Mon lunch). Tue is the ''urgent veg'' day — frittata + eggplant bowl + pepper skewers clear zucchini, eggplant, valeriana and bell peppers before May 12. Mid-week pivots to a slow-cooked white bean soup (Wed dinner, leftover Thu lunch). Cabbage, celeriac, parsnip, apples, pears, oranges and ginger anchor the back half. Frozen proteins: Chicken Breast thaws Sun→Mon dinner; Frozen Chicken Pieces thaw Mon→Tue dinner and Wed→Thu dinner; remaining Chicken Breast thaws Thu→Fri dinner. White beans soak Tue night for Wed soup. Csilla macros listed; Ralph auto-scaled (×1.31 kcal, ×1.32 protein). Fresh fish limited to mackerel this week — frozen sea bream/trout/turkey are already used.',TRUE);
INSERT INTO meal_days (id,meal_plan_id,day,date,focus,urgent,sort_order) VALUES ('332f279c-2134-4dd1-b986-7e93ad6485ae','06df96a1-3dd1-47d1-8ce9-0cfacbf511d9','Sunday','May 10','🍌 Banana · Smoked Mackerel start · Tomato & Valeriana',TRUE,0);
INSERT INTO meals (id,meal_day_id,type,emoji,name,tagline,kcal,protein,carbs,fat,tip,sort_order) VALUES ('c05e1ac1-3fcb-487c-ad31-0e9bb9d1782e','332f279c-2134-4dd1-b986-7e93ad6485ae','breakfast','🍓','Sunday Berry-Banana Yogurt Parfait with Toasted Oats','Forest fruits, ripe banana, sesame-toasted oats over creamy yogurt.',415,22,58,11,'Greek yogurt''s live cultures + oat beta-glucan = a probiotic + prebiotic combo that nourishes your gut microbiome — central to longevity. The frozen berries deliver anthocyanins (anti-inflammatory pigments) without spoiling concerns.',0);
INSERT INTO meal_priority (meal_id,label,urgent,sort_order) VALUES ('c05e1ac1-3fcb-487c-ad31-0e9bb9d1782e','Bananas',TRUE,0);
