INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('c05e1ac1-3fcb-487c-ad31-0e9bb9d1782e',0,'Toast oats and sesame seeds together in a dry pan over medium heat for 3-4 minutes, stirring constantly until golden and nutty. Tip onto a plate to cool.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('c05e1ac1-3fcb-487c-ad31-0e9bb9d1782e',1,'Spoon yogurt into two glasses or bowls. Layer with sliced banana and a handful of frozen forest fruits — let the berries weep their juice into the yogurt.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('c05e1ac1-3fcb-487c-ad31-0e9bb9d1782e',2,'Drizzle tahini and shower with the toasted oats and sesame.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('c05e1ac1-3fcb-487c-ad31-0e9bb9d1782e',3,'Finish with a pinch of cinnamon and a fine grating of lemon zest for brightness. Serve immediately.');
