INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('7d6806ba-aa88-456e-898a-d1ccde894692','057','Onions','1/4 red onion, finely sliced',TRUE,FALSE,7);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('7d6806ba-aa88-456e-898a-d1ccde894692','056','Garlic','1 clove, smashed',TRUE,FALSE,8);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('7d6806ba-aa88-456e-898a-d1ccde894692','055','Olive Oil','1.5 tbsp',TRUE,FALSE,9);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('7d6806ba-aa88-456e-898a-d1ccde894692','064','Mixed Spices','Smoked paprika, cumin, sumac, salt, pepper',TRUE,FALSE,10);
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('7d6806ba-aa88-456e-898a-d1ccde894692',0,'Rinse bulgur, then cook in 1.5x lightly salted water for 10 minutes until tender. Fluff with a fork and let steam off the heat.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('7d6806ba-aa88-456e-898a-d1ccde894692',1,'Pat the chickpeas very dry. Heat 1/2 tbsp olive oil in a skillet over medium-high heat with the smashed garlic. Add chickpeas, smoked paprika and cumin. Pan-crisp 6-7 minutes, shaking the pan, until they crackle and turn golden.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('7d6806ba-aa88-456e-898a-d1ccde894692',2,'Whisk tahini with lemon juice, a pinch of salt, and 2 tbsp warm water until creamy and pourable.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('7d6806ba-aa88-456e-898a-d1ccde894692',3,'Toss tomato wedges with sliced red onion, a drizzle of olive oil, a pinch of sumac and salt — let them macerate 5 minutes to draw the juices out.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('7d6806ba-aa88-456e-898a-d1ccde894692',4,'Build bowls: bulgur base, then valeriana, macerated tomatoes, crispy chickpeas, and crumbled feta. Drizzle generously with lemon-tahini, finish with lemon zest and cracked pepper.');
INSERT INTO meals (id,meal_day_id,type,emoji,name,tagline,kcal,protein,carbs,fat,tip,sort_order) VALUES ('f66341f2-e47a-4e1e-9efc-70275af990b5','332f279c-2134-4dd1-b986-7e93ad6485ae','dinner','🐟','Smoked Mackerel with Lemon-Smashed Potatoes & Arugula','Crisped potatoes, smoky fish, peppery rocket, golden lemon-butter.',595,32,42,30,'Smoked mackerel is one of the densest sources of EPA/DHA omega-3 (~2.5g per 100g) — these long-chain fats are central to brain health and longevity. Pairing with the cracked potato surface area lets the fragrant lemon-butter cling to every craggy edge.',2);
INSERT INTO meal_priority (meal_id,label,urgent,sort_order) VALUES ('f66341f2-e47a-4e1e-9efc-70275af990b5','Smoked Mackerel',TRUE,0);
INSERT INTO meal_priority (meal_id,label,urgent,sort_order) VALUES ('f66341f2-e47a-4e1e-9efc-70275af990b5','White Washed Potatoes',FALSE,1);
INSERT INTO meal_priority (meal_id,label,urgent,sort_order) VALUES ('f66341f2-e47a-4e1e-9efc-70275af990b5','Arugula',TRUE,2);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('f66341f2-e47a-4e1e-9efc-70275af990b5','070','Smoked Mackerel Fillet','110g (about half the pack)',FALSE,TRUE,0);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('f66341f2-e47a-4e1e-9efc-70275af990b5','068','White Washed Potatoes','350g, halved',FALSE,FALSE,1);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('f66341f2-e47a-4e1e-9efc-70275af990b5','008','Arugula / Rocket','1 small handful',FALSE,TRUE,2);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('f66341f2-e47a-4e1e-9efc-70275af990b5','041','Bio Lemons','1 lemon (juice + zest)',FALSE,FALSE,3);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('f66341f2-e47a-4e1e-9efc-70275af990b5','045','Kalamata Olives','8 olives, pitted and roughly chopped',TRUE,FALSE,4);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('f66341f2-e47a-4e1e-9efc-70275af990b5','056','Garlic','2 cloves, smashed',TRUE,FALSE,5);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('f66341f2-e47a-4e1e-9efc-70275af990b5','005','Cut Aromatic Herbs','1 heaped tbsp (dill-parsley mix)',FALSE,FALSE,6);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('f66341f2-e47a-4e1e-9efc-70275af990b5','044','Butter','1 tbsp',FALSE,FALSE,7);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('f66341f2-e47a-4e1e-9efc-70275af990b5','055','Olive Oil','1.5 tbsp',TRUE,FALSE,8);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('f66341f2-e47a-4e1e-9efc-70275af990b5','064','Mixed Spices','Black pepper, sea salt, chili flakes',TRUE,FALSE,9);
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('f66341f2-e47a-4e1e-9efc-70275af990b5',0,'Boil potatoes in salted water with 1 garlic clove for 18-20 minutes until fork-tender. Drain.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('f66341f2-e47a-4e1e-9efc-70275af990b5',1,'Tip potatoes onto a baking tray. Press each one lightly with the bottom of a glass to crack open. Drizzle with olive oil, salt, and pepper.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('f66341f2-e47a-4e1e-9efc-70275af990b5',2,'Roast at 220°C / 425°F for 18-20 minutes until edges are crisp and golden.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('f66341f2-e47a-4e1e-9efc-70275af990b5',3,'While potatoes crisp, flake the smoked mackerel into large, generous pieces, removing skin and any pin bones.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('f66341f2-e47a-4e1e-9efc-70275af990b5',4,'Make the dressing: warm butter and remaining smashed garlic in a small pan until just foaming, then off the heat add lemon juice, zest, chopped olives, and the herbs.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('f66341f2-e47a-4e1e-9efc-70275af990b5',5,'Plate: a bed of arugula, the crisped potatoes, mackerel flaked over the top, and the warm lemon-olive-herb butter spooned generously across everything. Crack pepper, finish with chili flakes.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('f66341f2-e47a-4e1e-9efc-70275af990b5',6,'⚠️ THAWING: Move the Chicken Breast (fresh) from freezer to fridge tonight to thaw for tomorrow''s dinner.');
INSERT INTO meals (id,meal_day_id,type,emoji,name,tagline,kcal,protein,carbs,fat,tip,sort_order) VALUES ('047ff6ac-f9c2-4770-95f9-1aec39be0b76','332f279c-2134-4dd1-b986-7e93ad6485ae','snack','🍎','Apple-Tahini Crunch with Toasted Sesame','Crisp apple, nutty tahini drizzle, cinnamon dust.',215,5,28,10,'Apple''s quercetin + sesame''s lignans are both polyphenols linked to lower inflammation. Tahini brings calcium and a steady dose of unsaturated fat to slow the apple''s natural sugar release.',3);
INSERT INTO meal_priority (meal_id,label,urgent,sort_order) VALUES ('047ff6ac-f9c2-4770-95f9-1aec39be0b76','Bio Apples',FALSE,0);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('047ff6ac-f9c2-4770-95f9-1aec39be0b76','039','Bio Apples','1 whole apple, sliced',FALSE,FALSE,0);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('047ff6ac-f9c2-4770-95f9-1aec39be0b76','046','Tahini (Sesame Paste)','1 tbsp',TRUE,FALSE,1);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('047ff6ac-f9c2-4770-95f9-1aec39be0b76','061','Sesame Seeds','1 tsp, toasted',TRUE,FALSE,2);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('047ff6ac-f9c2-4770-95f9-1aec39be0b76','064','Mixed Spices','Pinch of cinnamon',TRUE,FALSE,3);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('047ff6ac-f9c2-4770-95f9-1aec39be0b76','041','Bio Lemons','Squeeze (to keep apple from browning)',FALSE,FALSE,4);
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('047ff6ac-f9c2-4770-95f9-1aec39be0b76',0,'Slice the apple into thick wedges and toss with a tiny squeeze of lemon to keep them bright.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('047ff6ac-f9c2-4770-95f9-1aec39be0b76',1,'Loosen tahini with 1 tsp warm water until pourable.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('047ff6ac-f9c2-4770-95f9-1aec39be0b76',2,'Drizzle tahini over the apple, scatter toasted sesame seeds, dust with cinnamon. Eat with fingers.');
INSERT INTO meal_days (id,meal_plan_id,day,date,focus,urgent,sort_order) VALUES ('3d02b8ef-cc3f-40f9-b6f1-87bd42565d69','06df96a1-3dd1-47d1-8ce9-0cfacbf511d9','Monday','May 11','🍌 Last bananas · Mackerel finish · Last tomatoes · Cucumber',TRUE,1);
INSERT INTO meals (id,meal_day_id,type,emoji,name,tagline,kcal,protein,carbs,fat,tip,sort_order) VALUES ('eb688a61-8796-491b-b234-b1e449354bab','3d02b8ef-cc3f-40f9-b6f1-87bd42565d69','breakfast','🥣','Banana-Pear Cinnamon Oatmeal with Toasted Sesame','Slow-cooked oats, ripe banana, soft pear, sesame finish.',405,16,70,9,'The slow simmer breaks down oat beta-glucan into a soluble fiber gel that has been clinically shown to lower LDL cholesterol over time. Cinnamon adds insulin sensitivity benefits — paired with banana''s natural sugars, this is steady morning fuel.',0);
INSERT INTO meal_priority (meal_id,label,urgent,sort_order) VALUES ('eb688a61-8796-491b-b234-b1e449354bab','Bananas',TRUE,0);
INSERT INTO meal_priority (meal_id,label,urgent,sort_order) VALUES ('eb688a61-8796-491b-b234-b1e449354bab','LaDorna Milk',FALSE,1);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('eb688a61-8796-491b-b234-b1e449354bab','066','Fine Rolled Oats','60g',TRUE,FALSE,0);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('eb688a61-8796-491b-b234-b1e449354bab','065','LaDorna Milk','300ml',FALSE,FALSE,1);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('eb688a61-8796-491b-b234-b1e449354bab','011','Bananas','1 whole banana, sliced (use last)',FALSE,TRUE,2);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('eb688a61-8796-491b-b234-b1e449354bab','027','Bio Pears','1 whole pear, diced',FALSE,FALSE,3);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('eb688a61-8796-491b-b234-b1e449354bab','061','Sesame Seeds','1 tbsp, toasted',TRUE,FALSE,4);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('eb688a61-8796-491b-b234-b1e449354bab','046','Tahini (Sesame Paste)','1 tsp',TRUE,FALSE,5);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('eb688a61-8796-491b-b234-b1e449354bab','064','Mixed Spices','Cinnamon, cardamom pinch, sea salt',TRUE,FALSE,6);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('eb688a61-8796-491b-b234-b1e449354bab','041','Bio Lemons','Zest of 1/2 lemon',FALSE,FALSE,7);
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('eb688a61-8796-491b-b234-b1e449354bab',0,'Combine oats, milk, a pinch of salt and a generous shake of cinnamon in a small saucepan. Bring to a gentle simmer.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('eb688a61-8796-491b-b234-b1e449354bab',1,'Add half the diced pear and stir constantly over low heat for 6-8 minutes until creamy and the pear has softened into the porridge.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('eb688a61-8796-491b-b234-b1e449354bab',2,'Off the heat, fold in tahini and a pinch of cardamom. Spoon into bowls.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('eb688a61-8796-491b-b234-b1e449354bab',3,'Top with the remaining fresh pear, sliced banana, toasted sesame seeds, and lemon zest. Serve hot.');
INSERT INTO meals (id,meal_day_id,type,emoji,name,tagline,kcal,protein,carbs,fat,tip,sort_order) VALUES ('c65d75a9-7431-4904-9909-a9af862d7e9a','3d02b8ef-cc3f-40f9-b6f1-87bd42565d69','lunch','🌿','Smoked Mackerel Bulgur Tabbouleh with Cucumber & Last Tomatoes','Smoky fish, herby grains, bright cucumber crunch.',480,30,50,18,'Tabbouleh is traditionally herb-forward — the parsley delivers vitamin K and folate. The smoked mackerel turns this from a side into a complete protein-rich main, while the lemon''s vitamin C boosts the iron absorption from the herbs.',1);
INSERT INTO meal_priority (meal_id,label,urgent,sort_order) VALUES ('c65d75a9-7431-4904-9909-a9af862d7e9a','Smoked Mackerel',TRUE,0);
INSERT INTO meal_priority (meal_id,label,urgent,sort_order) VALUES ('c65d75a9-7431-4904-9909-a9af862d7e9a','Bio Tomatoes',TRUE,1);
INSERT INTO meal_priority (meal_id,label,urgent,sort_order) VALUES ('c65d75a9-7431-4904-9909-a9af862d7e9a','Bio Cucumbers',TRUE,2);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('c65d75a9-7431-4904-9909-a9af862d7e9a','070','Smoked Mackerel Fillet','100g (finish pack), flaked',FALSE,TRUE,0);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('c65d75a9-7431-4904-9909-a9af862d7e9a','048','Bulgur','60g dry',TRUE,FALSE,1);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('c65d75a9-7431-4904-9909-a9af862d7e9a','017','Bio Tomatoes','Remaining ~175g, finely diced (finish)',FALSE,TRUE,2);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('c65d75a9-7431-4904-9909-a9af862d7e9a','019','Bio Cucumbers','1 whole cucumber, finely diced',FALSE,TRUE,3);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('c65d75a9-7431-4904-9909-a9af862d7e9a','013','Spring Onions / Green Onions','3 stalks, finely sliced',FALSE,FALSE,4);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('c65d75a9-7431-4904-9909-a9af862d7e9a','005','Cut Aromatic Herbs','2 heaped tbsp (dill-parsley)',FALSE,FALSE,5);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('c65d75a9-7431-4904-9909-a9af862d7e9a','041','Bio Lemons','1 lemon, juiced',FALSE,FALSE,6);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('c65d75a9-7431-4904-9909-a9af862d7e9a','055','Olive Oil','2 tbsp extra-virgin',TRUE,FALSE,7);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('c65d75a9-7431-4904-9909-a9af862d7e9a','056','Garlic','1 small clove, microplaned',TRUE,FALSE,8);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('c65d75a9-7431-4904-9909-a9af862d7e9a','064','Mixed Spices','Sumac, sea salt, black pepper',TRUE,FALSE,9);
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('c65d75a9-7431-4904-9909-a9af862d7e9a',0,'Cook bulgur in 1.5x salted water for 10 minutes until tender. Drain any excess and spread on a tray to cool quickly so it stays fluffy.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('c65d75a9-7431-4904-9909-a9af862d7e9a',1,'Whisk dressing in a large bowl: lemon juice, olive oil, microplaned garlic, sumac, salt, pepper.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('c65d75a9-7431-4904-9909-a9af862d7e9a',2,'Add cooled bulgur, diced tomato, cucumber, spring onions, and the chopped herbs. Toss thoroughly and let sit 5 minutes for flavors to marry.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('c65d75a9-7431-4904-9909-a9af862d7e9a',3,'Flake the mackerel into generous pieces and fold through gently — you want to keep the chunks intact, not break them up.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('c65d75a9-7431-4904-9909-a9af862d7e9a',4,'Taste, adjust salt and lemon. Serve at room temperature in deep bowls with extra olive oil drizzle.');
INSERT INTO meals (id,meal_day_id,type,emoji,name,tagline,kcal,protein,carbs,fat,tip,sort_order) VALUES ('d586a8c2-e0fc-487f-9f63-fb783bf8cefa','3d02b8ef-cc3f-40f9-b6f1-87bd42565d69','dinner','🍗','Lemon-Garlic Chicken Breast with Sweet Pepper Sauté & Basmati','Pan-seared chicken, blistered peppers, fragrant rice.',605,45,58,18,'Resting chicken after searing is the single biggest difference between dry and juicy. The muscle fibers relax and reabsorb their juices — slicing too early means it all runs onto the board. Bell peppers double the vitamin C of a tomato, gram-for-gram.',2);
INSERT INTO meal_priority (meal_id,label,urgent,sort_order) VALUES ('d586a8c2-e0fc-487f-9f63-fb783bf8cefa','Chicken Breast',FALSE,0);
INSERT INTO meal_priority (meal_id,label,urgent,sort_order) VALUES ('d586a8c2-e0fc-487f-9f63-fb783bf8cefa','Bio Bell Peppers',TRUE,1);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('d586a8c2-e0fc-487f-9f63-fb783bf8cefa','004','Chicken Breast (fresh)','260g for two (thawed today)',FALSE,FALSE,0);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('d586a8c2-e0fc-487f-9f63-fb783bf8cefa','021','Bio Bell Peppers (red/yellow)','1 pepper, thickly sliced',FALSE,TRUE,1);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('d586a8c2-e0fc-487f-9f63-fb783bf8cefa','057','Onions','1 small onion, sliced',TRUE,FALSE,2);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('d586a8c2-e0fc-487f-9f63-fb783bf8cefa','056','Garlic','3 cloves, sliced',TRUE,FALSE,3);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('d586a8c2-e0fc-487f-9f63-fb783bf8cefa','047','Basmati Rice','120g dry',TRUE,FALSE,4);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('d586a8c2-e0fc-487f-9f63-fb783bf8cefa','041','Bio Lemons','1 lemon (zest + juice)',FALSE,FALSE,5);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('d586a8c2-e0fc-487f-9f63-fb783bf8cefa','005','Cut Aromatic Herbs','1 tbsp',FALSE,FALSE,6);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('d586a8c2-e0fc-487f-9f63-fb783bf8cefa','055','Olive Oil','1.5 tbsp',TRUE,FALSE,7);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('d586a8c2-e0fc-487f-9f63-fb783bf8cefa','044','Butter','1 tsp (to finish)',FALSE,FALSE,8);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('d586a8c2-e0fc-487f-9f63-fb783bf8cefa','064','Mixed Spices','Smoked paprika, oregano, sea salt, black pepper',TRUE,FALSE,9);
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('d586a8c2-e0fc-487f-9f63-fb783bf8cefa',0,'Butterfly each chicken breast horizontally so they''re an even thickness — this helps them cook quickly without drying out. Season generously with salt, pepper, paprika, and oregano. Rest 10 minutes at room temperature.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('d586a8c2-e0fc-487f-9f63-fb783bf8cefa',1,'Rinse rice until water runs clear. Cook in 1.5x salted water with the lemon zest, covered, on lowest heat for 12 minutes. Off the heat, steam another 5 min.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('d586a8c2-e0fc-487f-9f63-fb783bf8cefa',2,'Heat 1 tbsp olive oil in a heavy skillet until shimmering. Lay chicken in and don''t touch — let it form a deep golden crust, about 4 minutes. Flip, drop heat to medium, and cook another 3-4 minutes until just done.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('d586a8c2-e0fc-487f-9f63-fb783bf8cefa',3,'Transfer chicken to a plate, tent loosely, and let it rest 5 minutes (this is non-negotiable — it''s how you get juicy, not dry, chicken).');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('d586a8c2-e0fc-487f-9f63-fb783bf8cefa',4,'In the same pan, add the peppers, onion, and garlic with the remaining oil. Sauté over high heat 5-6 minutes until edges blister and char. Off the heat, stir in lemon juice, butter, and chopped herbs.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('d586a8c2-e0fc-487f-9f63-fb783bf8cefa',5,'Slice chicken against the grain, plate over rice with the pepper sauté alongside, and pour any resting juices back over. Finish with cracked pepper.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('d586a8c2-e0fc-487f-9f63-fb783bf8cefa',6,'⚠️ THAWING: Move 1 bag of Frozen Chicken Pieces from freezer to fridge tonight to thaw for tomorrow''s dinner.');
INSERT INTO meals (id,meal_day_id,type,emoji,name,tagline,kcal,protein,carbs,fat,tip,sort_order) VALUES ('3a05d951-289a-4c37-9d0c-dd0e1a0b96f6','3d02b8ef-cc3f-40f9-b6f1-87bd42565d69','snack','🌱','Pesto Hummus Crudités with Green Pepper & Celery','Cool crunchy vegetables in a vibrant green-pesto hummus.',230,8,22,13,'Chickpeas in hummus deliver fiber, plant protein, and resistant starch — three of the most consistent dietary markers in long-lived populations. Crunchy raw vegetables also slow eating speed, which improves satiety.',3);
INSERT INTO meal_priority (meal_id,label,urgent,sort_order) VALUES ('3a05d951-289a-4c37-9d0c-dd0e1a0b96f6','Hummus with Pesto',TRUE,0);
INSERT INTO meal_priority (meal_id,label,urgent,sort_order) VALUES ('3a05d951-289a-4c37-9d0c-dd0e1a0b96f6','Green Bell Pepper',TRUE,1);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('3a05d951-289a-4c37-9d0c-dd0e1a0b96f6','067','Hummus with Pesto','100g',FALSE,TRUE,0);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('3a05d951-289a-4c37-9d0c-dd0e1a0b96f6','022','Green Bell Pepper','1 whole pepper, into spears',FALSE,TRUE,1);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('3a05d951-289a-4c37-9d0c-dd0e1a0b96f6','031','Celery Stalks','2 stalks, into batons',FALSE,FALSE,2);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('3a05d951-289a-4c37-9d0c-dd0e1a0b96f6','061','Sesame Seeds','1 tsp, toasted',TRUE,FALSE,3);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('3a05d951-289a-4c37-9d0c-dd0e1a0b96f6','055','Olive Oil','1 tsp drizzle',TRUE,FALSE,4);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('3a05d951-289a-4c37-9d0c-dd0e1a0b96f6','041','Bio Lemons','Squeeze on the hummus',FALSE,FALSE,5);
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('3a05d951-289a-4c37-9d0c-dd0e1a0b96f6',0,'Spoon the pesto hummus into a shallow bowl. Make a swoosh with the back of the spoon and pool a teaspoon of olive oil into the well.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('3a05d951-289a-4c37-9d0c-dd0e1a0b96f6',1,'Squeeze in fresh lemon and shower with toasted sesame seeds.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('3a05d951-289a-4c37-9d0c-dd0e1a0b96f6',2,'Cut green pepper into spears and celery into batons. Arrange around the bowl and dunk.');
INSERT INTO meal_days (id,meal_plan_id,day,date,focus,urgent,sort_order) VALUES ('5155d559-7608-463f-9da9-7248e9b54d46','06df96a1-3dd1-47d1-8ce9-0cfacbf511d9','Tuesday','May 12','🥒 Urgent veg day · Zucchini · Eggplant · Valeriana · Peppers',TRUE,2);
INSERT INTO meals (id,meal_day_id,type,emoji,name,tagline,kcal,protein,carbs,fat,tip,sort_order) VALUES ('a18271f3-6177-4204-a531-104436b8c0af','5155d559-7608-463f-9da9-7248e9b54d46','breakfast','🥚','Zucchini-Feta Frittata with Arugula & Lemon','Soft eggs, ribbons of zucchini, salty feta, peppery rocket.',395,24,12,28,'Eggs are the gold standard for protein quality (PDCAAS = 1.0), with the yolk delivering choline — essential for liver and brain health. The squeezed-zucchini technique came from Mediterranean grandmothers and is non-negotiable for texture.',0);
INSERT INTO meal_priority (meal_id,label,urgent,sort_order) VALUES ('a18271f3-6177-4204-a531-104436b8c0af','Bio Zucchini',TRUE,0);
INSERT INTO meal_priority (meal_id,label,urgent,sort_order) VALUES ('a18271f3-6177-4204-a531-104436b8c0af','Arugula',TRUE,1);
INSERT INTO meal_priority (meal_id,label,urgent,sort_order) VALUES ('a18271f3-6177-4204-a531-104436b8c0af','Feta',FALSE,2);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('a18271f3-6177-4204-a531-104436b8c0af','043','Eggs','3 eggs, beaten',FALSE,FALSE,0);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('a18271f3-6177-4204-a531-104436b8c0af','020','Bio Zucchini','1 whole zucchini, coarsely grated',FALSE,TRUE,1);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('a18271f3-6177-4204-a531-104436b8c0af','034','Feta Cheese PDO','40g, crumbled',FALSE,FALSE,2);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('a18271f3-6177-4204-a531-104436b8c0af','008','Arugula / Rocket','Remaining handful (finish bag)',FALSE,TRUE,3);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('a18271f3-6177-4204-a531-104436b8c0af','005','Cut Aromatic Herbs','1 heaped tbsp',FALSE,FALSE,4);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('a18271f3-6177-4204-a531-104436b8c0af','013','Spring Onions / Green Onions','1 stalk, sliced',FALSE,FALSE,5);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('a18271f3-6177-4204-a531-104436b8c0af','056','Garlic','1 small clove, grated',TRUE,FALSE,6);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('a18271f3-6177-4204-a531-104436b8c0af','041','Bio Lemons','1/2 lemon (zest + juice for arugula)',FALSE,FALSE,7);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('a18271f3-6177-4204-a531-104436b8c0af','055','Olive Oil','1.5 tbsp',TRUE,FALSE,8);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('a18271f3-6177-4204-a531-104436b8c0af','064','Mixed Spices','Black pepper, sea salt, chili flakes',TRUE,FALSE,9);
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('a18271f3-6177-4204-a531-104436b8c0af',0,'Squeeze the grated zucchini hard in a clean tea towel — get out as much water as you can. This is the secret to a frittata that isn''t soggy.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('a18271f3-6177-4204-a531-104436b8c0af',1,'Heat 1 tbsp olive oil in a small (20cm) ovenproof skillet over medium heat. Sauté the zucchini, spring onion, and garlic 4-5 minutes until softened and any remaining moisture has cooked off.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('a18271f3-6177-4204-a531-104436b8c0af',2,'Beat eggs with salt, pepper, half the herbs, and lemon zest. Pour over the zucchini, sprinkle feta on top, and cook undisturbed 3 minutes until the bottom sets.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('a18271f3-6177-4204-a531-104436b8c0af',3,'Slide under a hot grill / broiler for 3-4 minutes until just set on top with a slight wobble in the centre — don''t overcook.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('a18271f3-6177-4204-a531-104436b8c0af',4,'Toss arugula with remaining olive oil, lemon juice, and a pinch of salt. Pile on top of the frittata, scatter remaining herbs and chili flakes. Slice into wedges.');
INSERT INTO meals (id,meal_day_id,type,emoji,name,tagline,kcal,protein,carbs,fat,tip,sort_order) VALUES ('9d57022d-da1f-4919-bb78-0c1af3f1d78f','5155d559-7608-463f-9da9-7248e9b54d46','lunch','🍆','Smoky Eggplant & Chickpea Bulgur Bowl with Lemon-Tahini','Charred eggplant, herby bulgur, valeriana, silky tahini drizzle.',510,19,70,18,'Roasting eggplant at high heat caramelizes its natural sugars and breaks down its fibers into a creamy texture — no need for the heavy oil-soak that ruins most home-cooked eggplant. Tahini adds 80mg of calcium per tbsp — sesame is one of the densest plant calcium sources.',1);
INSERT INTO meal_priority (meal_id,label,urgent,sort_order) VALUES ('9d57022d-da1f-4919-bb78-0c1af3f1d78f','Eggplant',TRUE,0);
INSERT INTO meal_priority (meal_id,label,urgent,sort_order) VALUES ('9d57022d-da1f-4919-bb78-0c1af3f1d78f','Valeriana',TRUE,1);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('9d57022d-da1f-4919-bb78-0c1af3f1d78f','024','Eggplant / Aubergine','1 whole eggplant, cubed',FALSE,TRUE,0);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('9d57022d-da1f-4919-bb78-0c1af3f1d78f','049','Canned Chickpeas','1/2 can (~200g), drained',TRUE,FALSE,1);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('9d57022d-da1f-4919-bb78-0c1af3f1d78f','048','Bulgur','60g dry',TRUE,FALSE,2);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('9d57022d-da1f-4919-bb78-0c1af3f1d78f','069','Valeriana (Lamb''s Lettuce)','Remaining 1/2 bag (finish)',FALSE,TRUE,3);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('9d57022d-da1f-4919-bb78-0c1af3f1d78f','046','Tahini (Sesame Paste)','1.5 tbsp',TRUE,FALSE,4);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('9d57022d-da1f-4919-bb78-0c1af3f1d78f','041','Bio Lemons','1 lemon, juiced',FALSE,FALSE,5);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('9d57022d-da1f-4919-bb78-0c1af3f1d78f','056','Garlic','2 cloves (1 for eggplant, 1 grated for sauce)',TRUE,FALSE,6);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('9d57022d-da1f-4919-bb78-0c1af3f1d78f','057','Onions','1/2 onion, finely sliced',TRUE,FALSE,7);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('9d57022d-da1f-4919-bb78-0c1af3f1d78f','055','Olive Oil','2 tbsp',TRUE,FALSE,8);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('9d57022d-da1f-4919-bb78-0c1af3f1d78f','061','Sesame Seeds','1 tsp toasted (garnish)',TRUE,FALSE,9);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('9d57022d-da1f-4919-bb78-0c1af3f1d78f','005','Cut Aromatic Herbs','1 tbsp (garnish)',FALSE,FALSE,10);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('9d57022d-da1f-4919-bb78-0c1af3f1d78f','064','Mixed Spices','Smoked paprika, cumin, coriander, sumac, salt',TRUE,FALSE,11);
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('9d57022d-da1f-4919-bb78-0c1af3f1d78f',0,'Toss eggplant cubes with 1.5 tbsp olive oil, smoked paprika, cumin, coriander, salt, and 1 sliced garlic clove. Spread on a tray with space between cubes — they steam if crowded.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('9d57022d-da1f-4919-bb78-0c1af3f1d78f',1,'Roast at 230°C / 450°F for 25 minutes, turning halfway, until deeply charred at the edges and silky-soft inside.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('9d57022d-da1f-4919-bb78-0c1af3f1d78f',2,'Cook bulgur in 1.5x salted water for 10 minutes; fluff and set aside.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('9d57022d-da1f-4919-bb78-0c1af3f1d78f',3,'Pan-warm chickpeas with sliced onion in 1/2 tbsp oil, 4-5 minutes, with a pinch of cumin until onion softens.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('9d57022d-da1f-4919-bb78-0c1af3f1d78f',4,'Whisk tahini with lemon juice, the grated garlic clove, salt, and 2-3 tbsp warm water until silky and pourable.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('9d57022d-da1f-4919-bb78-0c1af3f1d78f',5,'Build bowls: bulgur base, then valeriana, hot eggplant, warm chickpeas. Drizzle generously with the lemon-tahini sauce, scatter sesame and herbs, finish with sumac.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('9d57022d-da1f-4919-bb78-0c1af3f1d78f',6,'💧 SOAK TONIGHT: Cover the dried white beans with cold water and a pinch of bicarb in a large bowl. Leave on the counter overnight for tomorrow''s soup.');
INSERT INTO meals (id,meal_day_id,type,emoji,name,tagline,kcal,protein,carbs,fat,tip,sort_order) VALUES ('eb9af92b-5f24-4c78-8108-b9df0c416c80','5155d559-7608-463f-9da9-7248e9b54d46','dinner','🍢','Lemon-Oregano Chicken & Pepper Skewers with Quinoa','Charred peppers, golden chicken, lemon-herb quinoa.',615,44,52,22,'Quinoa is a complete plant protein — all 9 essential amino acids — and brings 50% more iron than rice. Charred peppers gain Maillard compounds (savory-sweet) without losing their vitamin C burst, which boosts the iron absorption from the quinoa.',2);
INSERT INTO meal_priority (meal_id,label,urgent,sort_order) VALUES ('eb9af92b-5f24-4c78-8108-b9df0c416c80','Frozen Chicken Pieces',FALSE,0);
INSERT INTO meal_priority (meal_id,label,urgent,sort_order) VALUES ('eb9af92b-5f24-4c78-8108-b9df0c416c80','Bio Bell Peppers',TRUE,1);
INSERT INTO meal_priority (meal_id,label,urgent,sort_order) VALUES ('eb9af92b-5f24-4c78-8108-b9df0c416c80','Bio Bell Peppers (red/yellow)',TRUE,2);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('eb9af92b-5f24-4c78-8108-b9df0c416c80','051','Frozen Chicken Pieces','400g (thawed today), cubed',FALSE,FALSE,0);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('eb9af92b-5f24-4c78-8108-b9df0c416c80','021','Bio Bell Peppers (red/yellow)','1 pepper, chunked (finish)',FALSE,TRUE,1);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('eb9af92b-5f24-4c78-8108-b9df0c416c80','057','Onions','1 red onion, wedged',TRUE,FALSE,2);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('eb9af92b-5f24-4c78-8108-b9df0c416c80','060','Quinoa','100g dry',TRUE,FALSE,3);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('eb9af92b-5f24-4c78-8108-b9df0c416c80','041','Bio Lemons','1.5 lemons (zest + juice)',FALSE,FALSE,4);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('eb9af92b-5f24-4c78-8108-b9df0c416c80','056','Garlic','3 cloves, microplaned',TRUE,FALSE,5);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('eb9af92b-5f24-4c78-8108-b9df0c416c80','005','Cut Aromatic Herbs','2 tbsp (parsley-dill)',FALSE,FALSE,6);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('eb9af92b-5f24-4c78-8108-b9df0c416c80','013','Spring Onions / Green Onions','1 stalk, sliced (garnish)',FALSE,FALSE,7);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('eb9af92b-5f24-4c78-8108-b9df0c416c80','055','Olive Oil','2 tbsp',TRUE,FALSE,8);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('eb9af92b-5f24-4c78-8108-b9df0c416c80','064','Mixed Spices','Oregano, sumac, smoked paprika, cumin, salt, pepper',TRUE,FALSE,9);
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('eb9af92b-5f24-4c78-8108-b9df0c416c80',0,'Marinate the cubed chicken: olive oil, juice of 1 lemon, microplaned garlic, oregano, paprika, cumin, salt, pepper. Toss well and rest 20 minutes (longer is fine).');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('eb9af92b-5f24-4c78-8108-b9df0c416c80',1,'Rinse quinoa thoroughly. Cook in 2x salted water for 12 minutes, then steam off heat 5 min. Fluff with a fork and dress with lemon zest, juice from 1/2 lemon, herbs, olive oil, and sliced spring onion.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('eb9af92b-5f24-4c78-8108-b9df0c416c80',2,'Thread skewers alternately: chicken, pepper chunk, onion wedge, repeat. Pack snugly so the chicken touches the vegetables — they baste each other.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('eb9af92b-5f24-4c78-8108-b9df0c416c80',3,'Heat a heavy grill pan or skillet very hot. Cook skewers 3 minutes per side over 4 sides (12 minutes total) until chicken is just cooked through and peppers carry deep char marks.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('eb9af92b-5f24-4c78-8108-b9df0c416c80',4,'Pile quinoa onto plates, lay skewers across, scatter sumac and any remaining herbs. Serve with lemon wedges to squeeze at the table.');
INSERT INTO meals (id,meal_day_id,type,emoji,name,tagline,kcal,protein,carbs,fat,tip,sort_order) VALUES ('db81465c-6a39-456e-b5dc-2e7b1a567955','5155d559-7608-463f-9da9-7248e9b54d46','snack','🍐','Pear with Cinnamon-Ginger Yogurt & Toasted Sesame','Juicy pear, fragrant ginger yogurt, sesame crunch.',220,10,30,7,'Ginger contains gingerol — a potent anti-inflammatory shown to reduce muscle soreness and lower CRP markers. Pairing with probiotic yogurt amplifies gut anti-inflammatory effects.',3);
INSERT INTO meal_priority (meal_id,label,urgent,sort_order) VALUES ('db81465c-6a39-456e-b5dc-2e7b1a567955','Bio Pears',FALSE,0);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('db81465c-6a39-456e-b5dc-2e7b1a567955','027','Bio Pears','1 whole pear, sliced',FALSE,FALSE,0);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('db81465c-6a39-456e-b5dc-2e7b1a567955','036','Greek / Creamy Yogurt','120g',FALSE,FALSE,1);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('db81465c-6a39-456e-b5dc-2e7b1a567955','040','Ginger Root','1cm piece, microplaned',FALSE,FALSE,2);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('db81465c-6a39-456e-b5dc-2e7b1a567955','061','Sesame Seeds','1 tsp, toasted',TRUE,FALSE,3);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('db81465c-6a39-456e-b5dc-2e7b1a567955','064','Mixed Spices','Cinnamon',TRUE,FALSE,4);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('db81465c-6a39-456e-b5dc-2e7b1a567955','046','Tahini (Sesame Paste)','1 tsp',TRUE,FALSE,5);
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('db81465c-6a39-456e-b5dc-2e7b1a567955',0,'Stir microplaned ginger and a generous shake of cinnamon into the yogurt.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('db81465c-6a39-456e-b5dc-2e7b1a567955',1,'Spoon yogurt into a small bowl, fan pear slices over the top.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('db81465c-6a39-456e-b5dc-2e7b1a567955',2,'Drizzle with tahini and shower with toasted sesame seeds.');
INSERT INTO meal_days (id,meal_plan_id,day,date,focus,urgent,sort_order) VALUES ('92544bdf-6bba-4ad9-a5fc-06637a956818','06df96a1-3dd1-47d1-8ce9-0cfacbf511d9','Wednesday','May 13','🫘 Slow soup day · Cabbage · Celeriac · White Beans',FALSE,3);
INSERT INTO meals (id,meal_day_id,type,emoji,name,tagline,kcal,protein,carbs,fat,tip,sort_order) VALUES ('c1d51a61-f70d-40cd-a487-cd02d6bf8b7b','92544bdf-6bba-4ad9-a5fc-06637a956818','breakfast','🍎','Apple-Cinnamon Overnight Oats with Yogurt & Tahini','Cool creamy oats, grated apple, warm cinnamon, sesame finish.',425,20,60,13,'Soaking oats overnight begins partial fermentation and softens phytic acid, which improves mineral absorption. The yogurt cultures continue working in the fridge, making this a quietly probiotic breakfast.',0);
INSERT INTO meal_priority (meal_id,label,urgent,sort_order) VALUES ('c1d51a61-f70d-40cd-a487-cd02d6bf8b7b','Bio Apples',FALSE,0);
INSERT INTO meal_priority (meal_id,label,urgent,sort_order) VALUES ('c1d51a61-f70d-40cd-a487-cd02d6bf8b7b','LaDorna Milk',TRUE,1);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('c1d51a61-f70d-40cd-a487-cd02d6bf8b7b','066','Fine Rolled Oats','55g',TRUE,FALSE,0);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('c1d51a61-f70d-40cd-a487-cd02d6bf8b7b','065','LaDorna Milk','200ml',FALSE,TRUE,1);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('c1d51a61-f70d-40cd-a487-cd02d6bf8b7b','036','Greek / Creamy Yogurt','100g',FALSE,FALSE,2);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('c1d51a61-f70d-40cd-a487-cd02d6bf8b7b','039','Bio Apples','1 whole apple (1/2 grated, 1/2 diced)',FALSE,FALSE,3);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('c1d51a61-f70d-40cd-a487-cd02d6bf8b7b','046','Tahini (Sesame Paste)','1 tbsp',TRUE,FALSE,4);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('c1d51a61-f70d-40cd-a487-cd02d6bf8b7b','061','Sesame Seeds','1 tsp',TRUE,FALSE,5);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('c1d51a61-f70d-40cd-a487-cd02d6bf8b7b','064','Mixed Spices','Cinnamon, ground ginger, sea salt pinch',TRUE,FALSE,6);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('c1d51a61-f70d-40cd-a487-cd02d6bf8b7b','041','Bio Lemons','Squeeze on grated apple',FALSE,FALSE,7);
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('c1d51a61-f70d-40cd-a487-cd02d6bf8b7b',0,'The night before: combine oats, milk, yogurt, grated half-apple, lemon squeeze, cinnamon, ground ginger, and a pinch of salt in a jar or bowl. Stir, cover, and fridge overnight.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('c1d51a61-f70d-40cd-a487-cd02d6bf8b7b',1,'In the morning, the oats will be plump and creamy. Stir well. If too thick, splash in extra milk.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('c1d51a61-f70d-40cd-a487-cd02d6bf8b7b',2,'Top with the diced fresh apple, drizzle of tahini, sesame seeds, and another shake of cinnamon.');
INSERT INTO meals (id,meal_day_id,type,emoji,name,tagline,kcal,protein,carbs,fat,tip,sort_order) VALUES ('fe7f6a21-f2a8-46a6-8945-7c2088b1be18','92544bdf-6bba-4ad9-a5fc-06637a956818','lunch','🥥','Coconut-Turmeric Cabbage & Chickpea Curry over Basmati','Silky coconut, ginger-bright cabbage, golden chickpeas.',495,17,65,18,'Turmeric''s curcumin is fat-soluble — coconut milk''s medium-chain fats are an excellent vehicle. Adding black pepper (in mixed spices) increases curcumin bioavailability up to 2000% via piperine. This is one of the most studied longevity-spice combinations.',1);
INSERT INTO meal_priority (meal_id,label,urgent,sort_order) VALUES ('fe7f6a21-f2a8-46a6-8945-7c2088b1be18','Cabbage',FALSE,0);
INSERT INTO meal_priority (meal_id,label,urgent,sort_order) VALUES ('fe7f6a21-f2a8-46a6-8945-7c2088b1be18','Coconut Milk',FALSE,1);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('fe7f6a21-f2a8-46a6-8945-7c2088b1be18','071','Cabbage','1/4 head, finely shredded',FALSE,FALSE,0);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('fe7f6a21-f2a8-46a6-8945-7c2088b1be18','049','Canned Chickpeas','1/2 can (~200g), drained (open second can)',TRUE,FALSE,1);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('fe7f6a21-f2a8-46a6-8945-7c2088b1be18','050','Coconut Milk','1/2 can (~200ml)',TRUE,FALSE,2);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('fe7f6a21-f2a8-46a6-8945-7c2088b1be18','047','Basmati Rice','120g dry',TRUE,FALSE,3);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('fe7f6a21-f2a8-46a6-8945-7c2088b1be18','057','Onions','1 onion, finely diced',TRUE,FALSE,4);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('fe7f6a21-f2a8-46a6-8945-7c2088b1be18','056','Garlic','3 cloves, microplaned',TRUE,FALSE,5);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('fe7f6a21-f2a8-46a6-8945-7c2088b1be18','040','Ginger Root','2cm piece, microplaned',FALSE,FALSE,6);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('fe7f6a21-f2a8-46a6-8945-7c2088b1be18','041','Bio Lemons','1/2 lemon, juiced',FALSE,FALSE,7);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('fe7f6a21-f2a8-46a6-8945-7c2088b1be18','055','Olive Oil','1 tbsp',TRUE,FALSE,8);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('fe7f6a21-f2a8-46a6-8945-7c2088b1be18','013','Spring Onions / Green Onions','1 stalk, sliced (garnish)',FALSE,FALSE,9);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('fe7f6a21-f2a8-46a6-8945-7c2088b1be18','005','Cut Aromatic Herbs','1 tbsp (garnish)',FALSE,FALSE,10);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('fe7f6a21-f2a8-46a6-8945-7c2088b1be18','064','Mixed Spices','Turmeric, cumin, coriander, mustard seed, chili flakes, salt',TRUE,FALSE,11);
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('fe7f6a21-f2a8-46a6-8945-7c2088b1be18',0,'Cook basmati rice in 1.5x salted water on lowest heat, covered, 12 minutes; steam off heat 5 min.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('fe7f6a21-f2a8-46a6-8945-7c2088b1be18',1,'Heat oil in a wide pan over medium heat. Add mustard seeds — when they pop, add diced onion. Cook 5-6 minutes until translucent and beginning to caramelize at the edges.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('fe7f6a21-f2a8-46a6-8945-7c2088b1be18',2,'Add garlic, ginger, turmeric, cumin, coriander. Stir 30 seconds until fragrant — don''t let the spices burn.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('fe7f6a21-f2a8-46a6-8945-7c2088b1be18',3,'Add shredded cabbage and a pinch of salt. Toss for 2 minutes to wilt slightly, then pour in coconut milk and 100ml water. Simmer 8 minutes until cabbage is tender but still has a little bite.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('fe7f6a21-f2a8-46a6-8945-7c2088b1be18',4,'Stir in chickpeas, lemon juice, and chili flakes to taste. Simmer another 3 minutes.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('fe7f6a21-f2a8-46a6-8945-7c2088b1be18',5,'Spoon over basmati rice, scatter spring onion and herbs.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('fe7f6a21-f2a8-46a6-8945-7c2088b1be18',6,'🫘 PREP CHECK: confirm white beans soaked in cold water from last night — drain and rinse, ready for tonight''s soup.');
INSERT INTO meals (id,meal_day_id,type,emoji,name,tagline,kcal,protein,carbs,fat,tip,sort_order) VALUES ('9bb5b964-b54c-4dbb-83f8-0307a6d87a11','92544bdf-6bba-4ad9-a5fc-06637a956818','dinner','🍲','Tuscan White Bean Soup with Cabbage, Celeriac & Lemon','Slow-cooked beans, earthy celeriac, lemon-rosemary kiss.',580,28,80,16,'White beans are nutritional powerhouses: 15g of fiber per cup, plant protein, magnesium, folate, and resistant starch that feeds your butyrate-producing gut bacteria. Long-simmered bean soups rank among the most consistent staples in Blue Zone (longevity) populations.',2);
INSERT INTO meal_priority (meal_id,label,urgent,sort_order) VALUES ('9bb5b964-b54c-4dbb-83f8-0307a6d87a11','White Beans',FALSE,0);
INSERT INTO meal_priority (meal_id,label,urgent,sort_order) VALUES ('9bb5b964-b54c-4dbb-83f8-0307a6d87a11','Celeriac',FALSE,1);
INSERT INTO meal_priority (meal_id,label,urgent,sort_order) VALUES ('9bb5b964-b54c-4dbb-83f8-0307a6d87a11','Cabbage',FALSE,2);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('9bb5b964-b54c-4dbb-83f8-0307a6d87a11','062','White Beans (dried)','200g dry (soaked overnight)',TRUE,FALSE,0);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('9bb5b964-b54c-4dbb-83f8-0307a6d87a11','038','Celeriac (root)','1 whole celeriac, peeled and cubed',FALSE,FALSE,1);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('9bb5b964-b54c-4dbb-83f8-0307a6d87a11','071','Cabbage','1/4 head, shredded',FALSE,FALSE,2);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('9bb5b964-b54c-4dbb-83f8-0307a6d87a11','057','Onions','1 large onion, diced',TRUE,FALSE,3);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('9bb5b964-b54c-4dbb-83f8-0307a6d87a11','056','Garlic','5 cloves, smashed',TRUE,FALSE,4);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('9bb5b964-b54c-4dbb-83f8-0307a6d87a11','041','Bio Lemons','1 lemon (zest + juice)',FALSE,FALSE,5);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('9bb5b964-b54c-4dbb-83f8-0307a6d87a11','055','Olive Oil','3 tbsp (1 for soup, 2 to finish)',TRUE,FALSE,6);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('9bb5b964-b54c-4dbb-83f8-0307a6d87a11','005','Cut Aromatic Herbs','2 tbsp (to finish)',FALSE,FALSE,7);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('9bb5b964-b54c-4dbb-83f8-0307a6d87a11','045','Kalamata Olives','10 olives, halved (to finish)',TRUE,FALSE,8);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('9bb5b964-b54c-4dbb-83f8-0307a6d87a11','064','Mixed Spices','Bay leaf, rosemary or thyme, black pepper, salt, chili flakes',TRUE,FALSE,9);
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('9bb5b964-b54c-4dbb-83f8-0307a6d87a11',0,'Drain and rinse the soaked beans. Cover with fresh cold water (1L+) in a heavy pot with 2 smashed garlic cloves and bay leaf. Bring to a boil, skim foam, then reduce to a bare simmer for 60-70 minutes until beans are creamy-tender. Salt only at the end (early salting toughens skins).');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('9bb5b964-b54c-4dbb-83f8-0307a6d87a11',1,'Meanwhile, sauté diced onion and remaining garlic in 1 tbsp olive oil over low heat for 10 minutes — let it go pale gold and sweet, not brown.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('9bb5b964-b54c-4dbb-83f8-0307a6d87a11',2,'Add cubed celeriac and rosemary, stir 2 minutes. Pour in 500ml of the bean cooking liquid plus enough water to cover, simmer 12 minutes until celeriac is fork-tender.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('9bb5b964-b54c-4dbb-83f8-0307a6d87a11',3,'Add shredded cabbage and cooked beans. Simmer 8 more minutes until cabbage softens. Season generously with salt, pepper, and lemon zest.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('9bb5b964-b54c-4dbb-83f8-0307a6d87a11',4,'Ladle into deep bowls. Drench with the finishing olive oil, scatter olives, herbs, and chili flakes. Squeeze lemon over each portion at the table.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('9bb5b964-b54c-4dbb-83f8-0307a6d87a11',5,'Save half the soup, cooled, in a sealed container for tomorrow''s lunch. The flavor deepens overnight.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('9bb5b964-b54c-4dbb-83f8-0307a6d87a11',6,'⚠️ THAWING: Move 1 bag of Frozen Chicken Pieces from freezer to fridge tonight to thaw for tomorrow''s dinner.');
INSERT INTO meals (id,meal_day_id,type,emoji,name,tagline,kcal,protein,carbs,fat,tip,sort_order) VALUES ('243a1a25-3125-4ade-a60f-1aca3f929495','92544bdf-6bba-4ad9-a5fc-06637a956818','snack','🥬','Last Pesto Hummus with Pear, Celery & Lemon','Crisp celery, juicy pear, vibrant green hummus.',215,7,26,11,'Celery''s apigenin is a flavone that crosses the blood-brain barrier and shows neuroprotective activity in studies. Pairing with chickpea fiber slows digestion of the pear''s natural sugars.',3);
INSERT INTO meal_priority (meal_id,label,urgent,sort_order) VALUES ('243a1a25-3125-4ade-a60f-1aca3f929495','Hummus with Pesto',TRUE,0);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('243a1a25-3125-4ade-a60f-1aca3f929495','067','Hummus with Pesto','Remaining tub (~80g) — finish',FALSE,TRUE,0);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('243a1a25-3125-4ade-a60f-1aca3f929495','027','Bio Pears','1 whole pear, sliced',FALSE,FALSE,1);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('243a1a25-3125-4ade-a60f-1aca3f929495','031','Celery Stalks','2 stalks, into batons',FALSE,FALSE,2);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('243a1a25-3125-4ade-a60f-1aca3f929495','061','Sesame Seeds','1 tsp toasted',TRUE,FALSE,3);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('243a1a25-3125-4ade-a60f-1aca3f929495','041','Bio Lemons','Squeeze',FALSE,FALSE,4);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('243a1a25-3125-4ade-a60f-1aca3f929495','055','Olive Oil','1 tsp drizzle',TRUE,FALSE,5);
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('243a1a25-3125-4ade-a60f-1aca3f929495',0,'Spoon the pesto hummus into a wide bowl, swoosh with the spoon, drizzle olive oil and squeeze lemon.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('243a1a25-3125-4ade-a60f-1aca3f929495',1,'Slice pear into thick wedges and cut celery into batons.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('243a1a25-3125-4ade-a60f-1aca3f929495',2,'Scatter sesame seeds over the hummus and dip with the fruit and vegetable batons. The pear-with-pesto-hummus combination is unexpectedly perfect.');
INSERT INTO meal_days (id,meal_plan_id,day,date,focus,urgent,sort_order) VALUES ('476f9552-f0b6-4cb5-9b58-89c4c1bb51e8','06df96a1-3dd1-47d1-8ce9-0cfacbf511d9','Thursday','May 14','🍊 Soup leftover · Citrus boost · Honey-mustard chicken',FALSE,4);
INSERT INTO meals (id,meal_day_id,type,emoji,name,tagline,kcal,protein,carbs,fat,tip,sort_order) VALUES ('8bf456d6-d1d8-49dc-92a4-557aeb1539cb','476f9552-f0b6-4cb5-9b58-89c4c1bb51e8','breakfast','🍊','Orange-Ginger Yogurt Bowl with Toasted Oat Crumble','Citrus segments, fragrant ginger yogurt, crunchy oat-sesame crumble.',410,22,56,11,'Citrus segments deliver vitamin C alongside hesperidin (a flavanone) — a combination shown to support endothelial (blood vessel) health. Tahini''s calcium plus yogurt''s calcium = around 30% of daily needs in this single bowl.',0);
INSERT INTO meal_priority (meal_id,label,urgent,sort_order) VALUES ('8bf456d6-d1d8-49dc-92a4-557aeb1539cb','Bio Oranges',FALSE,0);
INSERT INTO meal_priority (meal_id,label,urgent,sort_order) VALUES ('8bf456d6-d1d8-49dc-92a4-557aeb1539cb','Greek Yogurt',FALSE,1);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('8bf456d6-d1d8-49dc-92a4-557aeb1539cb','036','Greek / Creamy Yogurt','200g',FALSE,FALSE,0);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('8bf456d6-d1d8-49dc-92a4-557aeb1539cb','033','Bio Oranges','1 whole orange, segmented',FALSE,FALSE,1);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('8bf456d6-d1d8-49dc-92a4-557aeb1539cb','040','Ginger Root','1cm piece, microplaned',FALSE,FALSE,2);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('8bf456d6-d1d8-49dc-92a4-557aeb1539cb','066','Fine Rolled Oats','40g',TRUE,FALSE,3);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('8bf456d6-d1d8-49dc-92a4-557aeb1539cb','061','Sesame Seeds','1.5 tbsp',TRUE,FALSE,4);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('8bf456d6-d1d8-49dc-92a4-557aeb1539cb','046','Tahini (Sesame Paste)','2 tsp',TRUE,FALSE,5);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('8bf456d6-d1d8-49dc-92a4-557aeb1539cb','064','Mixed Spices','Cinnamon, cardamom pinch, sea salt',TRUE,FALSE,6);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('8bf456d6-d1d8-49dc-92a4-557aeb1539cb','055','Olive Oil','1 tsp (for crumble)',TRUE,FALSE,7);
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('8bf456d6-d1d8-49dc-92a4-557aeb1539cb',0,'Make a quick stovetop crumble: heat 1 tsp olive oil in a dry pan, add oats, sesame, a pinch of salt and cinnamon. Toast over medium heat 4-5 minutes until deeply golden. Stir in 1 tsp tahini at the end so it clumps. Tip onto a plate to crisp up.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('8bf456d6-d1d8-49dc-92a4-557aeb1539cb',1,'Stir microplaned ginger and a pinch of cardamom into the yogurt.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('8bf456d6-d1d8-49dc-92a4-557aeb1539cb',2,'Segment the orange with a sharp knife — slice off top and bottom, cut down the sides to expose flesh, then carve out segments between membranes (this is called ''supreming'' and looks beautiful).');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('8bf456d6-d1d8-49dc-92a4-557aeb1539cb',3,'Spoon yogurt into bowls, fan orange segments over the top, squeeze any captured juice over them.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('8bf456d6-d1d8-49dc-92a4-557aeb1539cb',4,'Scatter generously with the toasted oat-sesame crumble and finish with a drizzle of remaining tahini.');
INSERT INTO meals (id,meal_day_id,type,emoji,name,tagline,kcal,protein,carbs,fat,tip,sort_order) VALUES ('bd97a6d7-a919-4061-8595-0d5745a1f71c','476f9552-f0b6-4cb5-9b58-89c4c1bb51e8','lunch','🍲','Reheated Tuscan Bean Soup with Lemon & Olive Oil','Yesterday''s soup, deepened overnight, brightened with fresh lemon.',470,22,65,13,'Bean soups taste better the second day because the starch slowly migrates into the broth, building body, and the spices bloom further. The cold rest also lets fiber gels form, which improves the satiety effect.',1);
INSERT INTO meal_priority (meal_id,label,urgent,sort_order) VALUES ('bd97a6d7-a919-4061-8595-0d5745a1f71c','Bean Soup leftover',FALSE,0);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('bd97a6d7-a919-4061-8595-0d5745a1f71c','062','White Beans (dried)','Reheat half the soup made Wednesday',TRUE,FALSE,0);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('bd97a6d7-a919-4061-8595-0d5745a1f71c','041','Bio Lemons','1/2 lemon, juiced',FALSE,FALSE,1);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('bd97a6d7-a919-4061-8595-0d5745a1f71c','005','Cut Aromatic Herbs','1 tbsp fresh',FALSE,FALSE,2);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('bd97a6d7-a919-4061-8595-0d5745a1f71c','055','Olive Oil','2 tbsp finishing oil',TRUE,FALSE,3);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('bd97a6d7-a919-4061-8595-0d5745a1f71c','056','Garlic','1 clove, very thinly sliced',TRUE,FALSE,4);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('bd97a6d7-a919-4061-8595-0d5745a1f71c','064','Mixed Spices','Black pepper, chili flakes, sea salt',TRUE,FALSE,5);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('bd97a6d7-a919-4061-8595-0d5745a1f71c','045','Kalamata Olives','8 olives, halved',TRUE,FALSE,6);
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('bd97a6d7-a919-4061-8595-0d5745a1f71c',0,'Pour the saved bean soup into a pot. The beans will have absorbed broth and the soup will look thicker — splash in 100-150ml hot water to loosen if needed.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('bd97a6d7-a919-4061-8595-0d5745a1f71c',1,'Heat gently for 8-10 minutes — slow warming preserves the bean texture (boiling makes them mushy).');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('bd97a6d7-a919-4061-8595-0d5745a1f71c',2,'Meanwhile, sizzle the thinly sliced garlic in 1 tbsp olive oil over low heat for 1 minute — just until fragrant and pale gold.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('bd97a6d7-a919-4061-8595-0d5745a1f71c',3,'Ladle soup into bowls. Drizzle with the warm garlic-oil and remaining olive oil, scatter olives and fresh herbs, finish with lemon juice and chili flakes.');
INSERT INTO meals (id,meal_day_id,type,emoji,name,tagline,kcal,protein,carbs,fat,tip,sort_order) VALUES ('570e7b65-7b6a-4dd8-8a82-6d749299c3ac','476f9552-f0b6-4cb5-9b58-89c4c1bb51e8','dinner','🍯','Honey-Mustard Roasted Chicken with Parsnip & Buttered Peas','Caramelized chicken, sweet roasted parsnip, lemon-buttered peas.',615,42,50,25,'Parsnips are an unsung longevity vegetable — high in soluble fiber, potassium, and vitamin K, and they sweeten dramatically when roasted as their starches convert to sugars. Resting roasted chicken with the bone in the pan makes the resting juices part of the sauce.',2);
INSERT INTO meal_priority (meal_id,label,urgent,sort_order) VALUES ('570e7b65-7b6a-4dd8-8a82-6d749299c3ac','Frozen Chicken Pieces',FALSE,0);
INSERT INTO meal_priority (meal_id,label,urgent,sort_order) VALUES ('570e7b65-7b6a-4dd8-8a82-6d749299c3ac','Parsnip',FALSE,1);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('570e7b65-7b6a-4dd8-8a82-6d749299c3ac','051','Frozen Chicken Pieces','400g (thawed today)',FALSE,FALSE,0);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('570e7b65-7b6a-4dd8-8a82-6d749299c3ac','037','Parsnip','Whole 500g pack, batoned',FALSE,FALSE,1);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('570e7b65-7b6a-4dd8-8a82-6d749299c3ac','054','Frozen Peas','200g',FALSE,FALSE,2);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('570e7b65-7b6a-4dd8-8a82-6d749299c3ac','057','Onions','1 onion, wedged',TRUE,FALSE,3);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('570e7b65-7b6a-4dd8-8a82-6d749299c3ac','056','Garlic','4 cloves (whole, in skin)',TRUE,FALSE,4);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('570e7b65-7b6a-4dd8-8a82-6d749299c3ac','044','Butter','1 tbsp',FALSE,FALSE,5);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('570e7b65-7b6a-4dd8-8a82-6d749299c3ac','055','Olive Oil','2 tbsp',TRUE,FALSE,6);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('570e7b65-7b6a-4dd8-8a82-6d749299c3ac','041','Bio Lemons','1 lemon (zest + juice)',FALSE,FALSE,7);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('570e7b65-7b6a-4dd8-8a82-6d749299c3ac','005','Cut Aromatic Herbs','1 tbsp',FALSE,FALSE,8);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('570e7b65-7b6a-4dd8-8a82-6d749299c3ac','013','Spring Onions / Green Onions','1 stalk, sliced (garnish)',FALSE,FALSE,9);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('570e7b65-7b6a-4dd8-8a82-6d749299c3ac','064','Mixed Spices','Wholegrain mustard or mustard powder, thyme, paprika, salt, pepper, 1 tsp honey if available (optional)',TRUE,FALSE,10);
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('570e7b65-7b6a-4dd8-8a82-6d749299c3ac',0,'Pat the chicken pieces very dry with paper towel. Mix mustard, thyme, paprika, salt, pepper, lemon zest, and 1 tbsp olive oil into a paste. Coat the chicken thoroughly and rest 15 min.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('570e7b65-7b6a-4dd8-8a82-6d749299c3ac',1,'Toss parsnip batons and onion wedges with remaining olive oil, salt, pepper. Spread on a roasting tray with whole garlic cloves tucked between. Lay the chicken pieces on top so their juices baste the vegetables.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('570e7b65-7b6a-4dd8-8a82-6d749299c3ac',2,'Roast at 200°C / 400°F for 35-40 minutes, turning the chicken once at the 20-minute mark, until skin is deeply golden and chicken is cooked through (juices run clear).');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('570e7b65-7b6a-4dd8-8a82-6d749299c3ac',3,'Rest the chicken 5 minutes on a board.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('570e7b65-7b6a-4dd8-8a82-6d749299c3ac',4,'Meanwhile, melt butter in a small pan. Add frozen peas and 2 tbsp water; cover and cook 4 minutes. Off the heat, stir in lemon juice, herbs, and a generous crack of pepper.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('570e7b65-7b6a-4dd8-8a82-6d749299c3ac',5,'Plate: chicken over parsnip, peas alongside, squeeze the soft roasted garlic from skins onto everything, scatter spring onion.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('570e7b65-7b6a-4dd8-8a82-6d749299c3ac',6,'⚠️ THAWING: Move the remaining Chicken Breast (fresh) from freezer to fridge tonight to thaw for tomorrow''s dinner.');
INSERT INTO meals (id,meal_day_id,type,emoji,name,tagline,kcal,protein,carbs,fat,tip,sort_order) VALUES ('65576c0c-0370-49ca-a893-b3e53af8cd30','476f9552-f0b6-4cb5-9b58-89c4c1bb51e8','snack','🥕','Celery & Tahini-Yogurt Dip with Toasted Sesame','Crunchy celery, creamy lemon-tahini yogurt, sesame shower.',215,11,14,13,'This tahini-yogurt is one of the most flexible Mediterranean condiments — it works as a dip, a salad dressing, or a sauce for grain bowls. The acidity balances tahini''s richness and helps emulsify it into a silky texture.',3);
INSERT INTO meal_priority (meal_id,label,urgent,sort_order) VALUES ('65576c0c-0370-49ca-a893-b3e53af8cd30','Celery',FALSE,0);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('65576c0c-0370-49ca-a893-b3e53af8cd30','031','Celery Stalks','3 stalks, into batons',FALSE,FALSE,0);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('65576c0c-0370-49ca-a893-b3e53af8cd30','036','Greek / Creamy Yogurt','100g',FALSE,FALSE,1);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('65576c0c-0370-49ca-a893-b3e53af8cd30','046','Tahini (Sesame Paste)','1.5 tbsp',TRUE,FALSE,2);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('65576c0c-0370-49ca-a893-b3e53af8cd30','041','Bio Lemons','1/2 lemon, juiced',FALSE,FALSE,3);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('65576c0c-0370-49ca-a893-b3e53af8cd30','056','Garlic','1/2 small clove, microplaned',TRUE,FALSE,4);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('65576c0c-0370-49ca-a893-b3e53af8cd30','061','Sesame Seeds','1 tsp toasted',TRUE,FALSE,5);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('65576c0c-0370-49ca-a893-b3e53af8cd30','064','Mixed Spices','Sumac or smoked paprika, salt',TRUE,FALSE,6);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('65576c0c-0370-49ca-a893-b3e53af8cd30','055','Olive Oil','1 tsp',TRUE,FALSE,7);
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('65576c0c-0370-49ca-a893-b3e53af8cd30',0,'Whisk yogurt, tahini, lemon juice, microplaned garlic, and a pinch of salt until smooth and pale.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('65576c0c-0370-49ca-a893-b3e53af8cd30',1,'Spoon into a bowl, drizzle olive oil, dust with sumac or paprika, scatter toasted sesame.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('65576c0c-0370-49ca-a893-b3e53af8cd30',2,'Cut celery into batons and dunk.');
INSERT INTO meal_days (id,meal_plan_id,day,date,focus,urgent,sort_order) VALUES ('5b6d18f5-d2aa-4207-a040-03c38d6e25d3','06df96a1-3dd1-47d1-8ce9-0cfacbf511d9','Friday','May 15','🍐 Yogurt-pear · Chickpea pilaf · Lemon-caper chicken',FALSE,5);
INSERT INTO meals (id,meal_day_id,type,emoji,name,tagline,kcal,protein,carbs,fat,tip,sort_order) VALUES ('c85a64ba-45da-4bbb-8222-f54167c7529f','5b6d18f5-d2aa-4207-a040-03c38d6e25d3','breakfast','🍐','Roasted Pear with Yogurt & Toasted Oat Granola','Honeyed pear halves, vanilla-cinnamon yogurt, golden granola.',420,18,62,12,'Roasting pear breaks down its cell walls and concentrates natural sugars into a jammy texture — no added sweetener needed. The temperature contrast (warm fruit, cool yogurt) makes simple ingredients feel restaurant-special.',0);
INSERT INTO meal_priority (meal_id,label,urgent,sort_order) VALUES ('c85a64ba-45da-4bbb-8222-f54167c7529f','Bio Pears',FALSE,0);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('c85a64ba-45da-4bbb-8222-f54167c7529f','027','Bio Pears','1 whole pear, halved and cored',FALSE,FALSE,0);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('c85a64ba-45da-4bbb-8222-f54167c7529f','036','Greek / Creamy Yogurt','180g',FALSE,FALSE,1);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('c85a64ba-45da-4bbb-8222-f54167c7529f','066','Fine Rolled Oats','40g',TRUE,FALSE,2);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('c85a64ba-45da-4bbb-8222-f54167c7529f','061','Sesame Seeds','1 tbsp',TRUE,FALSE,3);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('c85a64ba-45da-4bbb-8222-f54167c7529f','046','Tahini (Sesame Paste)','2 tsp',TRUE,FALSE,4);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('c85a64ba-45da-4bbb-8222-f54167c7529f','044','Butter','1 tsp',FALSE,FALSE,5);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('c85a64ba-45da-4bbb-8222-f54167c7529f','041','Bio Lemons','Zest of 1/2 lemon',FALSE,FALSE,6);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('c85a64ba-45da-4bbb-8222-f54167c7529f','064','Mixed Spices','Cinnamon, cardamom, salt pinch',TRUE,FALSE,7);
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('c85a64ba-45da-4bbb-8222-f54167c7529f',0,'Preheat oven to 200°C / 400°F. Place pear halves cut-side up on a small tray, dot each with butter, dust with cinnamon. Roast 12-15 minutes until soft and the edges turn caramel-gold.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('c85a64ba-45da-4bbb-8222-f54167c7529f',1,'Meanwhile toast oats and sesame seeds in a dry pan over medium heat until deeply golden, about 4 minutes. Remove from heat and stir in 1 tsp tahini and a pinch of salt — this clumps the granola together.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('c85a64ba-45da-4bbb-8222-f54167c7529f',2,'Stir cardamom and lemon zest into the yogurt.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('c85a64ba-45da-4bbb-8222-f54167c7529f',3,'Spoon yogurt into bowls. Place a warm pear half on top, drizzle with remaining tahini and pan juices, scatter the granola generously.');
INSERT INTO meals (id,meal_day_id,type,emoji,name,tagline,kcal,protein,carbs,fat,tip,sort_order) VALUES ('e317a150-86c1-4b00-b139-3001e41c060a','5b6d18f5-d2aa-4207-a040-03c38d6e25d3','lunch','🌿','Lemony Chickpea Bulgur Pilaf with Spring Onion & Herbs','Fluffy grain, golden chickpeas, bright lemon, fresh herb shower.',485,18,75,13,'The pilaf method — toasting the grain in spiced oil before adding water — coats each kernel in fat so they cook up separate and fluffy instead of clumping. It''s the same principle behind perfect rice.',1);
INSERT INTO meal_priority (meal_id,label,urgent,sort_order) VALUES ('e317a150-86c1-4b00-b139-3001e41c060a','Canned Chickpeas',FALSE,0);
INSERT INTO meal_priority (meal_id,label,urgent,sort_order) VALUES ('e317a150-86c1-4b00-b139-3001e41c060a','Spring Onions',TRUE,1);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('e317a150-86c1-4b00-b139-3001e41c060a','048','Bulgur','100g dry',TRUE,FALSE,0);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('e317a150-86c1-4b00-b139-3001e41c060a','049','Canned Chickpeas','Remaining 1/2 can (~200g), drained — finish open can',TRUE,FALSE,1);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('e317a150-86c1-4b00-b139-3001e41c060a','013','Spring Onions / Green Onions','3 stalks, sliced',FALSE,TRUE,2);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('e317a150-86c1-4b00-b139-3001e41c060a','057','Onions','1 onion, finely diced',TRUE,FALSE,3);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('e317a150-86c1-4b00-b139-3001e41c060a','056','Garlic','2 cloves, sliced',TRUE,FALSE,4);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('e317a150-86c1-4b00-b139-3001e41c060a','005','Cut Aromatic Herbs','2 tbsp',FALSE,FALSE,5);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('e317a150-86c1-4b00-b139-3001e41c060a','041','Bio Lemons','1 lemon (zest + juice)',FALSE,FALSE,6);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('e317a150-86c1-4b00-b139-3001e41c060a','055','Olive Oil','2 tbsp',TRUE,FALSE,7);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('e317a150-86c1-4b00-b139-3001e41c060a','061','Sesame Seeds','1 tbsp toasted',TRUE,FALSE,8);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('e317a150-86c1-4b00-b139-3001e41c060a','064','Mixed Spices','Cumin, smoked paprika, allspice pinch, sumac, salt, pepper',TRUE,FALSE,9);
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('e317a150-86c1-4b00-b139-3001e41c060a',0,'Heat olive oil in a wide pan. Add diced onion and cook 8-10 minutes over medium-low heat until soft, sweet, and turning golden at the edges.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('e317a150-86c1-4b00-b139-3001e41c060a',1,'Add sliced garlic, cumin, paprika, allspice. Stir 30 seconds until fragrant.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('e317a150-86c1-4b00-b139-3001e41c060a',2,'Add bulgur and toast in the spice oil for 2 minutes — this is the key step for pilaf that isn''t gluey.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('e317a150-86c1-4b00-b139-3001e41c060a',3,'Pour in 220ml hot water and a pinch of salt. Bring to a simmer, cover, drop heat to lowest, and cook 12 minutes.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('e317a150-86c1-4b00-b139-3001e41c060a',4,'Off the heat, scatter chickpeas over the top, replace lid, and steam another 5 minutes — this gently warms the chickpeas without breaking them.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('e317a150-86c1-4b00-b139-3001e41c060a',5,'Fluff with a fork. Stir in lemon zest, juice, sumac, sliced spring onions, and herbs.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('e317a150-86c1-4b00-b139-3001e41c060a',6,'Serve in bowls with toasted sesame seeds, extra olive oil, and cracked pepper.');
INSERT INTO meals (id,meal_day_id,type,emoji,name,tagline,kcal,protein,carbs,fat,tip,sort_order) VALUES ('75fa87e9-8caa-460c-aaf0-8da8c758fd86','5b6d18f5-d2aa-4207-a040-03c38d6e25d3','dinner','🍋','Lemon-Caper Chicken with Cabbage Slaw & Crushed Potatoes','Pan-seared chicken, lemon-butter sauce, raw cabbage crunch.',605,46,50,22,'Massaging shredded cabbage with salt and acid is a classic Mediterranean trick — it draws out water and softens the texture so the cabbage ''wilts'' raw, making it easier to digest while keeping all the cruciferous sulforaphane benefits intact.',2);
INSERT INTO meal_priority (meal_id,label,urgent,sort_order) VALUES ('75fa87e9-8caa-460c-aaf0-8da8c758fd86','Chicken Breast',FALSE,0);
INSERT INTO meal_priority (meal_id,label,urgent,sort_order) VALUES ('75fa87e9-8caa-460c-aaf0-8da8c758fd86','White Washed Potatoes',FALSE,1);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('75fa87e9-8caa-460c-aaf0-8da8c758fd86','004','Chicken Breast (fresh)','300g for two (thawed Thursday night)',FALSE,FALSE,0);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('75fa87e9-8caa-460c-aaf0-8da8c758fd86','068','White Washed Potatoes','Remaining 350g, halved (finish bag)',FALSE,FALSE,1);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('75fa87e9-8caa-460c-aaf0-8da8c758fd86','071','Cabbage','1/4 head, shaved very thin',FALSE,FALSE,2);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('75fa87e9-8caa-460c-aaf0-8da8c758fd86','041','Bio Lemons','1.5 lemons (juice + zest)',FALSE,FALSE,3);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('75fa87e9-8caa-460c-aaf0-8da8c758fd86','045','Kalamata Olives','10 olives, chopped (in place of capers)',TRUE,FALSE,4);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('75fa87e9-8caa-460c-aaf0-8da8c758fd86','044','Butter','1 tbsp',FALSE,FALSE,5);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('75fa87e9-8caa-460c-aaf0-8da8c758fd86','055','Olive Oil','2 tbsp',TRUE,FALSE,6);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('75fa87e9-8caa-460c-aaf0-8da8c758fd86','056','Garlic','3 cloves, sliced',TRUE,FALSE,7);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('75fa87e9-8caa-460c-aaf0-8da8c758fd86','005','Cut Aromatic Herbs','1 tbsp',FALSE,FALSE,8);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('75fa87e9-8caa-460c-aaf0-8da8c758fd86','013','Spring Onions / Green Onions','1 stalk, sliced',FALSE,FALSE,9);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('75fa87e9-8caa-460c-aaf0-8da8c758fd86','061','Sesame Seeds','1 tsp toasted',TRUE,FALSE,10);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('75fa87e9-8caa-460c-aaf0-8da8c758fd86','064','Mixed Spices','Black pepper, sea salt, smoked paprika',TRUE,FALSE,11);
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('75fa87e9-8caa-460c-aaf0-8da8c758fd86',0,'Boil potatoes in salted water 18 minutes until fork-tender. Drain, smash lightly with the bottom of a glass, drizzle olive oil, salt, pepper, paprika. Roast at 220°C / 425°F for 18 minutes until golden-crisp.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('75fa87e9-8caa-460c-aaf0-8da8c758fd86',1,'Make the slaw: shave cabbage paper-thin, toss with lemon juice, salt, and a tiny drizzle of olive oil. Massage gently 30 seconds — this softens the cabbage and brightens the colour. Add sliced spring onion and let sit while you cook the chicken.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('75fa87e9-8caa-460c-aaf0-8da8c758fd86',2,'Butterfly chicken breasts so they''re an even thickness. Season with salt, pepper, paprika. Heat 1 tbsp olive oil in a heavy skillet over medium-high. Sear chicken 4 min per side without moving, until deeply golden. Transfer to a plate to rest 5 minutes.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('75fa87e9-8caa-460c-aaf0-8da8c758fd86',3,'In the same pan over low heat, melt butter with sliced garlic — let it foam gently 1 minute (don''t brown the garlic). Add chopped olives, lemon juice, lemon zest, herbs. Swirl into a glossy sauce.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('75fa87e9-8caa-460c-aaf0-8da8c758fd86',4,'Slice chicken against the grain. Plate with crushed potatoes and a generous handful of the cabbage slaw. Spoon the lemon-butter sauce over chicken, finish with sesame and cracked pepper.');
INSERT INTO meals (id,meal_day_id,type,emoji,name,tagline,kcal,protein,carbs,fat,tip,sort_order) VALUES ('af1c51ac-0785-4ac8-9369-2bd5156e9157','5b6d18f5-d2aa-4207-a040-03c38d6e25d3','snack','🍯','Cinnamon Yogurt with Pear Compote & Sesame','Warm spiced pear over cool yogurt, sesame finish.',220,11,30,7,'The temperature contrast plus warm-spice aroma makes this feel like dessert with one-third the sugar. Cardamom in particular has been studied for its blood-pressure-lowering effects.',3);
INSERT INTO meal_priority (meal_id,label,urgent,sort_order) VALUES ('af1c51ac-0785-4ac8-9369-2bd5156e9157','Bio Pears',FALSE,0);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('af1c51ac-0785-4ac8-9369-2bd5156e9157','027','Bio Pears','1 whole pear, diced',FALSE,FALSE,0);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('af1c51ac-0785-4ac8-9369-2bd5156e9157','036','Greek / Creamy Yogurt','120g',FALSE,FALSE,1);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('af1c51ac-0785-4ac8-9369-2bd5156e9157','044','Butter','1 tsp',FALSE,FALSE,2);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('af1c51ac-0785-4ac8-9369-2bd5156e9157','061','Sesame Seeds','1 tsp toasted',TRUE,FALSE,3);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('af1c51ac-0785-4ac8-9369-2bd5156e9157','046','Tahini (Sesame Paste)','1 tsp',TRUE,FALSE,4);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('af1c51ac-0785-4ac8-9369-2bd5156e9157','064','Mixed Spices','Cinnamon, ground ginger, cardamom pinch',TRUE,FALSE,5);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('af1c51ac-0785-4ac8-9369-2bd5156e9157','041','Bio Lemons','Squeeze',FALSE,FALSE,6);
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('af1c51ac-0785-4ac8-9369-2bd5156e9157',0,'Melt butter in a small pan. Add diced pear, cinnamon, ginger, cardamom, and a tiny squeeze of lemon. Cook over medium heat 4-5 minutes until pears are soft and glossy.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('af1c51ac-0785-4ac8-9369-2bd5156e9157',1,'Spoon yogurt into a small bowl, top with the warm pear compote, drizzle tahini, scatter sesame seeds. Eat while the pears are still warm against the cool yogurt.');
INSERT INTO meal_days (id,meal_plan_id,day,date,focus,urgent,sort_order) VALUES ('c9b2bb0c-27d1-4994-a416-11d314442be2','06df96a1-3dd1-47d1-8ce9-0cfacbf511d9','Saturday','May 16','🥥 Coconut curry · Saturday slow morning · Greek bowl',FALSE,6);
INSERT INTO meals (id,meal_day_id,type,emoji,name,tagline,kcal,protein,carbs,fat,tip,sort_order) VALUES ('e3f96643-6678-4286-b80d-1b6ffeaff434','c9b2bb0c-27d1-4994-a416-11d314442be2','breakfast','🫐','Saturday Berry Smoothie Bowl with Coconut Yogurt Drizzle','Frozen berries, creamy coconut, oat-sesame crunch.',415,18,60,14,'Frozen berries actually have higher antioxidant retention than ''fresh'' supermarket berries (which lose anthocyanins over storage), and they make a creamier blended texture without needing banana for sweetness or body.',0);
INSERT INTO meal_priority (meal_id,label,urgent,sort_order) VALUES ('e3f96643-6678-4286-b80d-1b6ffeaff434','Frozen Forest Fruits',FALSE,0);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('e3f96643-6678-4286-b80d-1b6ffeaff434','053','Frozen Forest Fruits','Remaining ~150g (finish bag)',FALSE,FALSE,0);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('e3f96643-6678-4286-b80d-1b6ffeaff434','036','Greek / Creamy Yogurt','150g',FALSE,FALSE,1);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('e3f96643-6678-4286-b80d-1b6ffeaff434','050','Coconut Milk','100ml (open the can today)',TRUE,FALSE,2);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('e3f96643-6678-4286-b80d-1b6ffeaff434','066','Fine Rolled Oats','30g',TRUE,FALSE,3);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('e3f96643-6678-4286-b80d-1b6ffeaff434','061','Sesame Seeds','1 tbsp toasted',TRUE,FALSE,4);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('e3f96643-6678-4286-b80d-1b6ffeaff434','046','Tahini (Sesame Paste)','1 tsp',TRUE,FALSE,5);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('e3f96643-6678-4286-b80d-1b6ffeaff434','040','Ginger Root','1cm piece, microplaned',FALSE,FALSE,6);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('e3f96643-6678-4286-b80d-1b6ffeaff434','041','Bio Lemons','Zest of 1/2 lemon',FALSE,FALSE,7);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('e3f96643-6678-4286-b80d-1b6ffeaff434','064','Mixed Spices','Cinnamon, cardamom pinch',TRUE,FALSE,8);
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('e3f96643-6678-4286-b80d-1b6ffeaff434',0,'Toast oats and sesame in a dry pan 4 minutes until golden and nutty. Set aside to cool.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('e3f96643-6678-4286-b80d-1b6ffeaff434',1,'Blend frozen forest fruits, half the yogurt, coconut milk, ginger, and lemon zest until thick and silky — like soft-serve. If too stiff, add a splash more coconut milk.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('e3f96643-6678-4286-b80d-1b6ffeaff434',2,'Spoon into bowls.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('e3f96643-6678-4286-b80d-1b6ffeaff434',3,'Stir cinnamon and cardamom into the remaining yogurt and dollop alongside the smoothie base — don''t fully mix, you want stripes.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('e3f96643-6678-4286-b80d-1b6ffeaff434',4,'Top with toasted oat-sesame crumble and a thin drizzle of tahini.');
INSERT INTO meals (id,meal_day_id,type,emoji,name,tagline,kcal,protein,carbs,fat,tip,sort_order) VALUES ('d7a739b5-ca27-4e63-ab82-9e995056ea81','c9b2bb0c-27d1-4994-a416-11d314442be2','lunch','🫒','Greek Quinoa Bowl with Olives, Feta & Spring Onion','Lemony quinoa, briny olives, last of the feta, herb shower.',470,19,56,19,'Quinoa''s protein contains all 9 essential amino acids — rare for a plant food. Pairing with feta''s saturated fat slows the carbohydrate uptake and keeps blood sugar steadier through the afternoon.',1);
INSERT INTO meal_priority (meal_id,label,urgent,sort_order) VALUES ('d7a739b5-ca27-4e63-ab82-9e995056ea81','Feta',FALSE,0);
INSERT INTO meal_priority (meal_id,label,urgent,sort_order) VALUES ('d7a739b5-ca27-4e63-ab82-9e995056ea81','Kalamata Olives',FALSE,1);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('d7a739b5-ca27-4e63-ab82-9e995056ea81','060','Quinoa','100g dry',TRUE,FALSE,0);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('d7a739b5-ca27-4e63-ab82-9e995056ea81','034','Feta Cheese PDO','Remaining ~25g, crumbled (finish)',FALSE,FALSE,1);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('d7a739b5-ca27-4e63-ab82-9e995056ea81','045','Kalamata Olives','12 olives, halved',TRUE,FALSE,2);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('d7a739b5-ca27-4e63-ab82-9e995056ea81','013','Spring Onions / Green Onions','Remaining stalks, sliced (finish bunch)',FALSE,FALSE,3);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('d7a739b5-ca27-4e63-ab82-9e995056ea81','005','Cut Aromatic Herbs','2 tbsp (finish what''s needed for dinner first)',FALSE,FALSE,4);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('d7a739b5-ca27-4e63-ab82-9e995056ea81','041','Bio Lemons','1 lemon (zest + juice)',FALSE,FALSE,5);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('d7a739b5-ca27-4e63-ab82-9e995056ea81','055','Olive Oil','2 tbsp extra-virgin',TRUE,FALSE,6);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('d7a739b5-ca27-4e63-ab82-9e995056ea81','056','Garlic','1 clove, microplaned',TRUE,FALSE,7);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('d7a739b5-ca27-4e63-ab82-9e995056ea81','061','Sesame Seeds','1 tsp toasted',TRUE,FALSE,8);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('d7a739b5-ca27-4e63-ab82-9e995056ea81','064','Mixed Spices','Oregano, sumac, black pepper, salt',TRUE,FALSE,9);
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('d7a739b5-ca27-4e63-ab82-9e995056ea81',0,'Rinse quinoa thoroughly under cold water — this removes the bitter saponin coating. Cook in 2x salted water for 12 minutes, then steam off heat 5 minutes. Fluff with a fork and spread on a tray to cool slightly.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('d7a739b5-ca27-4e63-ab82-9e995056ea81',1,'Whisk lemon juice, olive oil, microplaned garlic, oregano, salt, pepper into a dressing.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('d7a739b5-ca27-4e63-ab82-9e995056ea81',2,'Toss the warm-but-not-hot quinoa with the dressing — warm grains absorb dressing best, but if too hot they kill the freshness of the herbs.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('d7a739b5-ca27-4e63-ab82-9e995056ea81',3,'Fold in olives, spring onion, and herbs. Crumble feta over the top — don''t stir it in, you want pure white pockets.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('d7a739b5-ca27-4e63-ab82-9e995056ea81',4,'Finish with lemon zest, sumac, sesame seeds, and an extra glug of olive oil. Eat at room temperature in deep bowls.');
INSERT INTO meals (id,meal_day_id,type,emoji,name,tagline,kcal,protein,carbs,fat,tip,sort_order) VALUES ('ee9235a2-3e94-4730-ac7d-f1233ea3146e','c9b2bb0c-27d1-4994-a416-11d314442be2','dinner','🍛','Slow-Coconut Cabbage & Chickpea Curry with Ginger over Basmati','Silky coconut curry, ginger-bright cabbage, fragrant rice.',595,22,80,22,'Long-caramelized onions plus toasted whole spices is the foundation of nearly every great curry — most home curries fail because the onion stage is rushed. Cabbage in coconut curry is a longevity classic across Indian and Sri Lankan cooking — cruciferous vegetables + fat-soluble turmeric = peak nutrient absorption.',2);
INSERT INTO meal_priority (meal_id,label,urgent,sort_order) VALUES ('ee9235a2-3e94-4730-ac7d-f1233ea3146e','Cabbage',FALSE,0);
INSERT INTO meal_priority (meal_id,label,urgent,sort_order) VALUES ('ee9235a2-3e94-4730-ac7d-f1233ea3146e','Coconut Milk',FALSE,1);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('ee9235a2-3e94-4730-ac7d-f1233ea3146e','071','Cabbage','Remaining 1/2 head, shredded (finish)',FALSE,FALSE,0);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('ee9235a2-3e94-4730-ac7d-f1233ea3146e','050','Coconut Milk','Remaining ~200ml (finish can)',TRUE,FALSE,1);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('ee9235a2-3e94-4730-ac7d-f1233ea3146e','049','Canned Chickpeas','1 can (~400g) — this opens the second can; refrigerate any unused',TRUE,FALSE,2);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('ee9235a2-3e94-4730-ac7d-f1233ea3146e','047','Basmati Rice','120g dry',TRUE,FALSE,3);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('ee9235a2-3e94-4730-ac7d-f1233ea3146e','040','Ginger Root','3cm piece, microplaned',FALSE,FALSE,4);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('ee9235a2-3e94-4730-ac7d-f1233ea3146e','056','Garlic','4 cloves, microplaned',TRUE,FALSE,5);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('ee9235a2-3e94-4730-ac7d-f1233ea3146e','057','Onions','1 large onion, finely diced',TRUE,FALSE,6);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('ee9235a2-3e94-4730-ac7d-f1233ea3146e','041','Bio Lemons','1 lemon, juiced',FALSE,FALSE,7);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('ee9235a2-3e94-4730-ac7d-f1233ea3146e','055','Olive Oil','2 tbsp',TRUE,FALSE,8);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('ee9235a2-3e94-4730-ac7d-f1233ea3146e','054','Frozen Peas','150g (finish what''s needed)',FALSE,FALSE,9);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('ee9235a2-3e94-4730-ac7d-f1233ea3146e','005','Cut Aromatic Herbs','1 tbsp (garnish)',FALSE,FALSE,10);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('ee9235a2-3e94-4730-ac7d-f1233ea3146e','061','Sesame Seeds','1 tsp toasted (garnish)',TRUE,FALSE,11);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('ee9235a2-3e94-4730-ac7d-f1233ea3146e','064','Mixed Spices','Turmeric, cumin, coriander, mustard seed, garam masala or curry powder, chili flakes, salt',TRUE,FALSE,12);
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('ee9235a2-3e94-4730-ac7d-f1233ea3146e',0,'Rinse rice until water runs clear. Cook in 1.5x salted water with a knob of butter on lowest heat, covered, 12 minutes; steam off heat 5 min.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('ee9235a2-3e94-4730-ac7d-f1233ea3146e',1,'Heat olive oil in a wide deep pan. Add mustard seeds — when they pop and dance, add diced onion and cook 8-10 minutes over medium-low until deeply caramelized at the edges. This long onion cook is the flavor backbone — don''t rush it.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('ee9235a2-3e94-4730-ac7d-f1233ea3146e',2,'Add garlic, ginger, turmeric, cumin, coriander, garam masala. Stir 1 minute until the kitchen smells like a proper curry house.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('ee9235a2-3e94-4730-ac7d-f1233ea3146e',3,'Add shredded cabbage with a pinch of salt and toss for 3 minutes to wilt slightly.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('ee9235a2-3e94-4730-ac7d-f1233ea3146e',4,'Pour in coconut milk and 150ml water. Bring to a gentle simmer, cover, and cook 15 minutes — the cabbage should be tender but still hold its shape.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('ee9235a2-3e94-4730-ac7d-f1233ea3146e',5,'Stir in chickpeas, frozen peas, and lemon juice. Simmer uncovered another 5 minutes until peas are bright green and the sauce has thickened slightly.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('ee9235a2-3e94-4730-ac7d-f1233ea3146e',6,'Taste and balance: more salt, more lemon, chili flakes for heat.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('ee9235a2-3e94-4730-ac7d-f1233ea3146e',7,'Serve over basmati rice, scatter herbs and toasted sesame, and finish with extra lemon at the table.');
INSERT INTO meals (id,meal_day_id,type,emoji,name,tagline,kcal,protein,carbs,fat,tip,sort_order) VALUES ('969d69df-d260-4de2-a813-b186bf583e39','c9b2bb0c-27d1-4994-a416-11d314442be2','snack','🍊','Orange-Ginger Yogurt with Sesame & Cinnamon','Sweet citrus, fragrant yogurt, sesame finish.',215,11,26,8,'Eating citrus segments rather than juice keeps all the soluble fiber and slows sugar absorption — the same vitamin C with a much steadier blood sugar response.',3);
INSERT INTO meal_priority (meal_id,label,urgent,sort_order) VALUES ('969d69df-d260-4de2-a813-b186bf583e39','Bio Oranges',FALSE,0);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('969d69df-d260-4de2-a813-b186bf583e39','033','Bio Oranges','1 whole orange, segmented',FALSE,FALSE,0);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('969d69df-d260-4de2-a813-b186bf583e39','036','Greek / Creamy Yogurt','120g',FALSE,FALSE,1);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('969d69df-d260-4de2-a813-b186bf583e39','040','Ginger Root','1cm piece, microplaned',FALSE,FALSE,2);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('969d69df-d260-4de2-a813-b186bf583e39','061','Sesame Seeds','1 tsp toasted',TRUE,FALSE,3);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('969d69df-d260-4de2-a813-b186bf583e39','046','Tahini (Sesame Paste)','1 tsp',TRUE,FALSE,4);
INSERT INTO meal_ingredients (meal_id,pantry_item_id,name,amount,is_pantry_staple,urgent,sort_order) VALUES ('969d69df-d260-4de2-a813-b186bf583e39','064','Mixed Spices','Cinnamon, cardamom pinch',TRUE,FALSE,5);
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('969d69df-d260-4de2-a813-b186bf583e39',0,'Stir microplaned ginger, cinnamon, and a tiny pinch of cardamom into the yogurt.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('969d69df-d260-4de2-a813-b186bf583e39',1,'Segment the orange (cut off top and bottom, slice down the sides to expose flesh, supreme out segments between membranes). Squeeze the leftover membrane over the yogurt for extra juice.');
INSERT INTO meal_steps (meal_id,step_order,instruction) VALUES ('969d69df-d260-4de2-a813-b186bf583e39',2,'Layer yogurt and orange segments in a small glass. Drizzle tahini and shower toasted sesame on top.');
